export const HLC_HUE_CATEGORIES = [
  "All", "Red", "Orange", "Yellow", "Yellow-Green", "Green",
  "Cyan", "Blue", "Violet", "Purple", "Magenta", "Pink"
];

export function searchHLC(query: string): HLCColor[] {
  const q = query.toLowerCase().trim();
  if (!q) return HLC_COLORS;
  return HLC_COLORS.filter(c =>
    c.name.toLowerCase().includes(q) ||
    c.id.toLowerCase().includes(q) ||
    c.hex.toLowerCase().includes(q) ||
    c.hueName.toLowerCase().includes(q)
  );
}

